// Pega todos os itens de entrada
const items = $input.all();

// Array de saída (OBRIGATÓRIO)
let out = [];

// Função para extrair o texto do ChatGPT
function extractText(j) {
  return (
    j?.output?.[0]?.content?.[0]?.text ??
    j?.output?.[0]?.content?.find?.(c => c.type === 'output_text')?.text ??
    j?.text ??
    j?.message?.content ??
    j?.output ??
    null
  );
}

// Remove ``` e parseia JSON com segurança
function safeParseJson(text) {
  if (typeof text !== 'string') return text;

  const cleaned = text
    .replace(/```[a-zA-Z]*\n?/g, '')
    .replace(/```/g, '')
    .trim();

  return JSON.parse(cleaned);
}

// Processa cada item
for (const item of items) {
  const rawText = extractText(item.json);

  if (!rawText) {
    throw new Error("Não encontrei texto da IA");
  }

  const parsed = safeParseJson(rawText);

  // Aceita objeto único ou array
  const list = Array.isArray(parsed) ? parsed : [parsed];

  for (const u of list) {
    out.push({
      json: {
        Projeto: String(u.Projeto || u.projeto || "SEM NOME"),
      ID: typeof u.ID === "number" ? u.ID : null,
      Cliente: String(u.Cliente || "INDEFINIDO"),
      Descrição: String(u["Descrição"] || ""),
      Observações: String(u["Observações"] || "")
      }
    });
  }
}

// RETORNO FINAL (OBRIGATÓRIO)
return out;

